INSERT INTO "map_points" ("created_at", "title", "coordinates", "type", "flag_is_meeting", "flag_has_socket", "flag_disabled", "description") VALUES
	('2026-04-23 11:09:00+00', 'Кофейня Obolenskiy', '{76.9449905,43.2561288}', 'point', true, true, false, 'Место встречи у кофейни на старушке. Уважают моноколесников, есть розетка'),
	('2025-10-15 16:33:00+00', 'Кок-Тобе', '{76.974923,43.233583}', 'point', false, false, false, 'Одна из самых известных смотровых точек города: с вершины открывается панорама Алматы. На вершине расположен парк, прогулочные аллеи, кафе и смотровые площадки, а также Алматинская телебашня.'),
	('2025-10-15 16:33:00+00', 'Сайран', '{76.867765,43.237843}', 'point', true, false, false, 'Есть резиновое покрытие для обучения на моноколесе'),
	('2025-10-15 16:33:00+00', 'Плотина Есентай', '{76.932896,43.219106}', 'point', true, false, false, 'Место встречи для старта в сторону Медео или по новому терренкуру'),
	('2026-04-27 18:53:00+00', 'Смотровая площадка у Аэропортовского озера', '{76.9869449264334,43.3348438873536}', 'point', false, false, false, ''),
	('2025-10-15 16:33:00+00', 'Замок дяди Вани', '{76.793656,43.116331}', 'point', false, false, false, 'Каменный замок или каменная крепость в Аксайском ущелье, которую более 30 лет собственноручно строил архитектор-любитель Иван Плотников'),
	('2025-10-15 16:33:00+00', 'Ягуар', '{76.935397,43.190456}', 'point', false, false, false, 'Велосипедная трасса, найдена на канале RollAllDay'),
	('2025-10-15 16:33:00+00', 'Р-н Каргалы (каргалинка)', '{76.866243,43.157895}', 'point', false, false, false, 'Радом конная ферма'),
	('2025-10-15 16:33:00+00', 'Памп-трек', '{76.984305,43.32182}', 'point', false, false, false, 'Асфальтовые кочки, тренировка коленей и подвески'),
	('2025-10-15 16:33:00+00', 'Стадион в 8 микрорайоне', '{76.869417,43.226284}', 'point', false, false, false, 'Резиновое покрытие. Подходит для обучения на моноколесе'),
	('2025-10-15 16:33:00+00', 'Смотровая площадка Горный гигант', '{76.946536,43.184724}', 'point', false, false, false, 'Вид на город'),
	('2025-10-15 16:33:00+00', 'Грушевые сады', '{76.9752972222222,43.1778138888889}', 'point', false, false, false, 'Весной приезжайте на цветение, а в сентябре собирать урожай!'),
	('2025-10-26 09:40:00+00', 'Бутаковское ущелье', '{77.094007,43.179827}', 'point', false, false, false, 'Бутаковское ущелье — одно из самых доступных и популярных горных ущелий в окрестностях Алматы, расположенное на северном склоне Заилийского Алатау'),
	('2025-10-15 16:33:00+00', 'Розетка на Атакенте', '{76.904882,43.222252}', 'socket', false, true, false, 'Розетка у входа в 10 павильон'),
	('2026-04-23 10:28:00+00', 'Розетка в КазНУ', '{76.92247,43.2225}', 'socket', false, true, false, 'Множество розеток между лавочками'),
	('2025-10-15 16:33:00+00', 'Розетка в коворкинге Яндекса', '{77.050713,43.162939}', 'socket', false, true, false, 'Последний ларек там где подьемник, внутри десятики розеток. Работает только во время работы канатной дороги'),
	('2025-10-15 16:33:00+00', 'Центральный парк (Парк Горького)', '{76.9716042280197,43.2657257313598}', 'point', true, true, false, 'Место встречи - скамейки за прудом. Розетка сзади туалета'),
	('2025-10-15 16:33:00+00', 'Визит Центр Аюсай', '{76.944726,43.101416}', 'point', true, true, false, 'Есть розетки, нужно договориться с охраной'),
	('2026-04-27 08:51:00+00', 'Дерево на Сункаре', '{76.9365609048745,43.2096634237518}', 'point', false, false, false, 'Обзорная точка'),
	('2026-04-23 11:04:00+00', 'Розетка в парке 28 Панфиловцев', '{76.95288,43.257259}', 'socket', false, true, false, 'У кафе Кофе-бара был летник со столиками и к каждому столику подводился провод с розеткой. Но официант постоянно был сильно занят и можно было на халяву заряжаться. \n\nпочти халявная розетка 😏'),
	('2026-04-23 11:02:00+00', 'Розетка возле входа в глобус', '{76.904851,43.239991}', 'socket', false, true, false, 'Возле центрального входа в глобус, с правой стороны на улице есть две розетки'),
	('2026-04-23 11:01:00+00', 'Розетка возле входа в Мегу', '{76.890635,43.202465}', 'socket', false, true, false, 'Возле центрального входа в мегу со стороны речки, с левой стороны есть розетка. На улице'),
	('2025-10-15 16:33:00+00', 'Розетка на плотине Медео', '{77.062469,43.150624}', 'socket', false, true, false, 'Розетка в электрощите справа от бинокля, за бортиком'),
	('2025-10-15 16:33:00+00', 'Розетка на трамплинах Сункар', '{76.9334042072296,43.2106213986928}', 'socket', false, true, false, 'Розетка у входа в gorilla energy park'),
	('2025-10-15 16:33:00+00', 'Розетка по дороге на Шымбулак', '{77.074944,43.133556}', 'socket', false, true, false, 'Розетка на электрощите сзади'),
	('2025-10-15 16:33:00+00', 'Розетка в Баханди', '{76.951021,43.24287}', 'socket', false, true, false, 'Бесплатная розетка на стене бургерной'),
	('2026-03-08 17:00:00+00', 'Смотровая площадка по дороге на Кок-тобе', '{76.9740472591055,43.2293673220757}', 'point', false, false, false, 'Смотровая площадка на половине пути до Кок-тобе'),
	('2025-10-15 16:33:00+00', 'Четыре бочки', '{76.977806,43.182579}', 'point', false, false, false, 'Обзорная точка. С неё открывается потрясающий вид на город'),
